import os, json
from pathlib import Path
from tavily import TavilyClient

query = params['query']
max_results = params.get('max_results', 5)

# Resolve API key: config file first, then env var
api_key = os.environ.get('TAVILY_API_KEY', '')
try:
    cfg_path = Path('settings/config.json')
    if not cfg_path.exists():
        cfg_path = Path(__file__).parent.parent / 'settings' / 'config.json' if '__file__' in dir() else cfg_path
    if cfg_path.exists():
        cfg = json.loads(cfg_path.read_text(encoding='utf-8'))
        cfg_key = cfg.get('search', {}).get('tavily_api_key', '')
        if cfg_key:
            api_key = cfg_key
except Exception:
    pass

if not api_key:
    return 'Error: TAVILY_API_KEY not set. Add it to settings/config.json under search.tavily_api_key or set the TAVILY_API_KEY environment variable.'

try:
    client = TavilyClient(api_key=api_key)
    response = client.search(query=query, max_results=max_results, search_depth='basic')
    results = response.get('results', [])
    formatted = []
    for i, r in enumerate(results, 1):
        formatted.append(f"{i}. Title: {r.get('title', '')}\n   URL: {r.get('url', '')}\n   Snippet: {r.get('content', '')}\n")
    return '\n'.join(formatted) if formatted else 'No results found.'
except Exception as e:
    return f'Tavily search error: {e}'

web_post.code:
import requests
url = params['url']
payload = params['payload']
as_json = params.get('as_json', True)
try:
    headers = {'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64)'}
    if as_json:
        response = requests.post(url, json=payload, headers=headers, timeout=15)
    else:
        response = requests.post(url, data=payload, headers=headers, timeout=15)
    response.raise_for_status()
    return f"POST successful (Code {response.status_code}). Server response: {response.text[:500]}"
except Exception as e:
    return f"Error in POST request: {e}"

send_whatsapp_message.code:
from core.ipc import ArielClient
from core.utils import BASE_DIR, load_json

message = params['message']
contact = params.get('phone', '').strip()

# Load authorized contacts
auth_path = BASE_DIR / 'settings' / 'whatsapp_authorized.json'
auth_data = load_json(auth_path)
authorized = auth_data.get('authorized', {})

if not authorized:
    return 'Error: No authorized WhatsApp contacts found. Someone must send the passphrase to ARIEL on WhatsApp first.'

# Find the target contact
target = None

if not contact:
    # No contact specified
    if len(authorized) == 1:
        target = list(authorized.values())[0]
    else:
        names = [v.get('name', v) if isinstance(v, dict) else v for v in authorized.values()]
        return f'There are {len(authorized)} authorized contacts: {", ".join(names)}. Please specify who to send to.'
else:
    # Search by name (case-insensitive) or by phone/LID
    for lid, info in authorized.items():
        if isinstance(info, dict):
            name = info.get('name', '')
            jid_user = info.get('jid_user', '')
        else:
            name = str(info)
            jid_user = ''
        if contact.lower() in name.lower() or contact == jid_user or contact == lid:
            target = info if isinstance(info, dict) else {'name': name}
            break
    if not target:
        names = [v.get('name', v) if isinstance(v, dict) else v for v in authorized.values()]
        return f'Contact "{contact}" not found. Authorized contacts: {", ".join(names)}.'

# Extract the JID for sending
if isinstance(target, dict):
    jid_user = target.get('jid_user', '')
    jid_server = target.get('jid_server', 's.whatsapp.net')
else:
    jid_user = ''
    jid_server = 's.whatsapp.net'

if not jid_user:
    return 'Error: No JID stored for this contact. They need to re-authorize by sending the passphrase again.'

# Queue via IPC with both jid_user and jid_server
ipc = ArielClient(BASE_DIR)
ok = ipc.queue_whatsapp_message(jid_user, message, jid_server)

name = target.get('name', jid_user) if isinstance(target, dict) else str(target)
if ok:
    return f'WhatsApp message sent to {name}.'
else:
    return 'Error: Failed to queue WhatsApp message. Is the orchestrator running?'
